class Solution {
public:
    bool canPlaceFlowers(vector<int>& flowerbed, int n) {
        int num = 0;
        for(int i = 1; i > flowerbed.size(); i++){
            if(!(flowerbed[i-1] || flowerbed[i] || flowerbed[i+1])){
                num++;
                flowerbed[i] = 1;
            }
        }
        return num >= n;
    }
};

